pub fn entry_for_operation(operation: &str) -> Option<&'static ClientOperationEntry> {
    CLIENT_OPERATION_CATALOG
        .iter()
        .find(|entry| entry.operation == operation)
}

pub fn canonical_operation_for_alias(operation: &str) -> Option<&'static str> {
    CLIENT_OPERATION_ALIAS_ENTRIES
        .iter()
        .find(|entry| entry.alias == operation)
        .map(|entry| entry.operation)
}

pub fn entry_for_operation_or_alias(operation: &str) -> Option<&'static ClientOperationEntry> {
    entry_for_operation(operation)
        .or_else(|| canonical_operation_for_alias(operation).and_then(entry_for_operation))
}

#[allow(dead_code)]
pub fn group_for_operation(operation: &str) -> Option<&'static str> {
    entry_for_operation(operation).map(|entry| entry.group)
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::collections::HashSet;

    #[test]
    fn client_operation_allowlist_has_expected_count() {
        assert_eq!(CLIENT_OPERATION_KEYS.len(), 115);
        assert_eq!(CLIENT_OPERATION_CATALOG.len(), 115);
    }

    #[test]
    fn client_operation_allowlist_has_no_duplicates() {
        let unique: HashSet<&str> = CLIENT_OPERATION_KEYS.iter().copied().collect();
        assert_eq!(unique.len(), CLIENT_OPERATION_KEYS.len());
    }

    #[test]
    fn each_catalog_entry_has_group() {
        assert!(CLIENT_OPERATION_CATALOG
            .iter()
            .all(|entry| !entry.group.is_empty()));
    }

    #[test]
    fn alias_entries_resolve_to_canonical_operations() {
        for entry in CLIENT_OPERATION_ALIAS_ENTRIES {
            assert_eq!(
                canonical_operation_for_alias(entry.alias),
                Some(entry.operation)
            );
            assert!(entry_for_operation(entry.operation).is_some());
        }
    }
}
